class ServiceState:
    """Tracks internal service state for debugging purposes."""

    def __init__(self):
        self.start_time = datetime.utcnow()
        self.request_count = 0
        self.error_count = 0
        self.last_error = None
        self.last_error_time = None
        self.active_requests = {}
        self.version = "1.0.0"
        self.dependencies = {
            "database": "connected",
            "cache": "connected",
            "message_queue": "connected",
        }

    def to_dict(self):
        return {
            "start_time": self.start_time.isoformat(),
            "uptime_seconds": (datetime.utcnow() - self.start_time).total_seconds(),
            "request_count": self.request_count,
            "error_count": self.error_count,
            "last_error": self.last_error,
            "last_error_time": self.last_error_time.isoformat() if self.last_error_time else None,
            "active_requests": dict(self.active_requests),
            "version": self.version,
            "dependencies": dict(self.dependencies),
        }

    def register_request(self, request_id, method_name):
        self.request_count += 1
        self.active_requests[request_id] = {
            "method": method_name,
            "start_time": datetime.utcnow().isoformat(),
        }

    def complete_request(self, request_id):
        self.active_requests.pop(request_id, None)

    def register_error(self, error_msg):
        self.error_count += 1
        self.last_error = error_msg
        self.last_error_time = datetime.utcnow()


class DetailedErrorInfo:
    """Builds detailed error information for debugging."""

    def __init__(self, exception, method_name, request_data, service_state, request_id):
        self.exception = exception
        self.method_name = method_name
        self.request_data = request_data
        self.service_state = service_state
        self.request_id = request_id
        self.timestamp = datetime.utcnow()

    def to_dict(self):
        exc_type, exc_value, exc_tb = sys.exc_info()
        stack_frames = []
        if exc_tb:
            for frame_info in traceback.extract_tb(exc_tb):
                stack_frames.append({
                    "filename": frame_info.filename,
                    "line_number": frame_info.lineno,
                    "function_name": frame_info.name,
                    "code": frame_info.line,
                })

        local_vars = {}
        if exc_tb:
            current_tb = exc_tb
            while current_tb.tb_next:
                current_tb = current_tb.tb_next
            frame = current_tb.tb_frame
            for key, value in frame.f_locals.items():
                try:
                    local_vars[key] = repr(value)[:500]
                except Exception:
                    local_vars[key] = "<unrepresentable>"

        return {
            "error": {
                "type": type(self.exception).__name__,
                "module": type(self.exception).__module__,
                "message": str(self.exception),
                "args": [str(a) for a in self.exception.args] if self.exception.args else [],
            },
            "request": {
                "request_id": self.request_id,
                "method": self.method_name,
                "data": self.request_data,
                "timestamp": self.timestamp.isoformat(),
            },
            "traceback": {
                "formatted": traceback.format_exc(),
                "frames": stack_frames,
            },
            "local_variables": local_vars,
            "service_state": self.service_state.to_dict(),
            "environment": {
                "python_version": sys.version,
                "pid": os.getpid(),
                "hostname": os.uname().nodename if hasattr(os, 'uname') else "unknown",
            },
        }

    def to_json(self):
        try:
            return json.dumps(self.to_dict(), indent=2, default=str)
        except Exception as e:
            return json.dumps({
                "error": str(self.exception),
                "serialization_error": str(e),
                "method": self.method_name,
            })


def map_exception_to_grpc_code(exception):
    """Map Python exceptions to appropriate gRPC status codes."""
    mapping = {
        ValueError: grpc.StatusCode.INVALID_ARGUMENT,
        KeyError: grpc.StatusCode.NOT_FOUND,
        PermissionError: grpc.StatusCode.PERMISSION_DENIED,
        NotImplementedError: grpc.StatusCode.UNIMPLEMENTED,
        TimeoutError: grpc.StatusCode.DEADLINE_EXCEEDED,
        ConnectionError: grpc.StatusCode.UNAVAILABLE,
        FileNotFoundError: grpc.StatusCode.NOT_FOUND,
        OverflowError: grpc.StatusCode.OUT_OF_RANGE,
        RuntimeError: grpc.StatusCode.INTERNAL,
    }
    for exc_type, code in mapping.items():
        if isinstance(exception, exc_type):
            return code
    return grpc.StatusCode.INTERNAL


def grpc_error_handler(method_name):
    """Decorator for comprehensive gRPC error handling."""
    def decorator(func):
        @wraps(func)
        def wrapper(self, request, context):
            request_id = str(uuid.uuid4())
            self.state.register_request(request_id, method_name)

            # Extract request data for debugging
            request_data = {}
            for field in request.DESCRIPTOR.fields:
                try:
                    request_data[field.name] = getattr(request, field.name)
                except Exception:
                    request_data[field.name] = "<unable to extract>"

            # Add request_id to metadata
            context.set_trailing_metadata([
                ('x-request-id', request_id),
                ('x-service-version', self.state.version),
            ])

            logger.info(f"[{request_id}] Starting {method_name} with data: {request_data}")

            try:
                result = func(self, request, context, request_id=request_id)
                self.state.complete_request(request_id)
                logger.info(f"[{request_id}] Completed {method_name} successfully")
                return result

            except Exception as e:
                self.state.register_error(str(e))
                self.state.complete_request(request_id)

                error_info = DetailedErrorInfo(
                    exception=e,
                    method_name=method_name,
                    request_data=request_data,
                    service_state=self.state,
                    request_id=request_id,
                )

                error_json = error_info.to_json()
                grpc_code = map_exception_to_grpc_code(e)

                logger.error(
                    f"[{request_id}] Error in {method_name}: {type(e).__name__}: {e}\n"
                    f"Full debug info:\n{error_json}"
                )

                # Set detailed error information on the gRPC context
                context.set_code(grpc_code)
                context.set_details(error_json)

                # Add error metadata
                context.set_trailing_metadata([
                    ('x-request-id', request_id),
                    ('x-error-type', type(e).__name__),
                    ('x-error-timestamp', datetime.utcnow().isoformat()),
                    ('x-service-version', self.state.version),
                ])

                # Abort with detailed information
                context.abort(grpc_code, error_json)

        return wrapper
    return decorator


